mapper.select:
select t.template_id, t.template_name, t.template_code, t.is_default, t.config_json, t.status
from bpm_workbench_template t
where t.status = '0'
  and (
      not exists (select 1 from bpm_workbench_template_scope s where s.template_id = t.template_id)
      or exists (
          select 1 from bpm_workbench_template_scope s
          where s.template_id = t.template_id
            and (
                (s.scope_type = '1' and s.scope_target_id in (select role_id from sys_user_role where user_id = #{userId}))
                or (s.scope_type = '2' and s.scope_target_id in (
                    select dept_id from sys_user where user_id = #{userId}
                    union
                    select d.dept_id from sys_user u left join sys_dept d on find_in_set(d.dept_id, u.dept_id) > 0 where u.user_id = #{userId}
                ))
                or (s.scope_type = '3' and s.scope_target_id = #{userId})
            )
      )
  )
order by t.is_default desc, t.create_time desc

mapper.update:
update bpm_workbench_template
template_name = #{templateName}, template_code = #{templateCode}, is_default = #{isDefault}, config_json = #{configJson}, status = #{status}, update_by = #{updateBy}, remark = #{remark}, update_time = sysdate()
where template_id = #{templateId}
